# Models module - defines base classes and interfaces

interface IIdentifiable:
    def get_id(self) -> int

interface IPrintable:
    def to_display(self) -> str

class Entity(IIdentifiable):
    _id: int

    def __init__(self, id: int):
        self._id = id

    @virtual
    def get_id(self) -> int:
        return self._id

class Person(Entity, IPrintable):
    _name: str

    def __init__(self, id: int, name: str):
        super().__init__(id)
        self._name = name

    @property
    get name(self) -> str:
        return self._name

    @override
    def get_id(self) -> int:
        return self._id * 100

    def to_display(self) -> str:
        return f"Person({self._name}, id={self._id})"

class Product(Entity, IPrintable):
    _sku: str
    _price: float

    def __init__(self, id: int, sku: str, price: float):
        super().__init__(id)
        self._sku = sku
        self._price = price

    @property
    get sku(self) -> str:
        return self._sku

    @property
    get price(self) -> float:
        return self._price

    def to_display(self) -> str:
        return f"Product({self._sku}, ${self._price})"

def create_test_person() -> Person:
    return Person(1, "Alice")

def create_test_product() -> Product:
    return Product(100, "LAPTOP-001", 999.99)

