# Utils module - imports from models and provides helper functions
from models import Entity, Person, Product, IIdentifiable, IPrintable

def describe_entity(e: Entity) -> str:
    return f"Entity with ID: {e.get_id()}"

def show_identifiable(obj: IIdentifiable) -> str:
    return f"ID={obj.get_id()}"

def format_printable(p: IPrintable) -> str:
    return p.to_display()

def process_entity_list(items: list[Entity]) -> list[str]:
    result: list[str] = []
    for item in items:
        result.append(describe_entity(item))
    return result

def create_person_clone(p: Person) -> Person:
    return Person(p.get_id(), p.name)
